<?php
/**
 * GuestRoomPDF.php
 *
 * Overlays reservation data onto the actual BatStateU Hostel
 * registration form (embedded as base64 images — no external files needed).
 *
 * Place at: BSU_HRS/admin/GuestRoomPDF.php
 * Requires: composer require tecnickcom/tcpdf  (run inside BSU_HRS/)
 */
class GuestRoomPDF
{
    private array $data;

    public function __construct(array $reservationData)
    {
        $this->data = $reservationData;
    }

    // ── Public API ────────────────────────────────────────────────────────────

    public function generate(): string
    {
        $pdf = $this->boot();
        $this->renderPage1($pdf);
        $this->renderPage2($pdf);
        $this->renderPage3($pdf);
        return $pdf->Output('', 'S');
    }

    public function stream(string $filename = 'guest_registration.pdf', bool $download = false): void
    {
        $pdf = $this->boot();
        $this->renderPage1($pdf);
        $this->renderPage2($pdf);
        $this->renderPage3($pdf);
        $pdf->Output($filename, $download ? 'D' : 'I');
    }

    // ── Bootstrap ─────────────────────────────────────────────────────────────

    private function boot(): \TCPDF
    {
        $autoload = dirname(__DIR__) . '/vendor/autoload.php';
        if (!file_exists($autoload)) {
            throw new RuntimeException('Composer autoload not found. Run: composer require tecnickcom/tcpdf');
        }
        require_once $autoload;

        $pdf = new \TCPDF('P', 'mm', 'A4', true, 'UTF-8', false);
        $pdf->SetCreator('BSU HRS');
        $pdf->SetAuthor('BatStateU Hostel - Nasugbu');
        $pdf->SetTitle('Hostel Room Registration - ' . ($this->data['booking_no'] ?? ''));
        $pdf->setPrintHeader(false);
        $pdf->setPrintFooter(false);
        $pdf->SetMargins(0, 0, 0);
        $pdf->SetAutoPageBreak(false, 0);
        return $pdf;
    }

    // ── Background helper ─────────────────────────────────────────────────────
    // Decodes the embedded base64 image and draws it full-page.

    private function bg(\TCPDF $pdf, string $b64): void
    {
        $raw = '@' . base64_decode($b64);
        $pdf->Image($raw, 0, 0, 210, 297, 'JPG', '', '', false, 200, '', false, false, 0, false, false, false);
    }

    // ── Text helper ───────────────────────────────────────────────────────────
    // x, y in mm from top-left corner of the page.

    private function put(\TCPDF $pdf, float $x, float $y, string $text, float $size = 9.5): void
    {
        $text = trim($text);
        if ($text === '') return;
        $pdf->SetFont('helvetica', '', $size);
        $pdf->SetTextColor(0, 0, 0);
        $pdf->SetXY($x, $y);
        $pdf->Cell(0, 0, $text, 0, 0, 'L', false, '', 0, false, 'T', 'M');
    }

    // ── Page 1 ────────────────────────────────────────────────────────────────

    private function renderPage1(\TCPDF $pdf): void
    {
        $pdf->AddPage();
        $this->bgFile($pdf, 1);

        $d = $this->data;
        [$last, $first, $mi] = $this->splitName((string)($d['guest_name'] ?? ''));

        // Principal guest name
        $this->put($pdf,  72.0, 93.5,  $last);
        $this->put($pdf, 125.0, 93.5,  $first);
        $this->put($pdf, 172.0, 93.5,  $mi);

        // Personal info
        $this->put($pdf, 48.0, 107.5, $this->fmtDate((string)($d['guest_dob']      ?? '')));
        $this->put($pdf, 48.0, 117.5, $this->trunc((string)($d['guest_address']    ?? ''), 65));
        $this->put($pdf, 48.0, 127.5, (string)($d['guest_email']   ?? ''));
        $this->put($pdf, 48.0, 137.5, (string)($d['guest_contact'] ?? ''));

        // Other guests — 4 slots on page 1
        $others = $this->decodeGuests($d['other_guests'] ?? '[]');
        $guestYs = [153.5, 162.5, 171.5, 180.5];
        foreach ($guestYs as $i => $gy) {
            $g    = $others[$i] ?? null;
            $name = $g ? trim((string)($g['name'] ?? '')) : '';
            $age  = $g ? trim((string)($g['age']  ?? '')) : '';
            $dob  = $g ? $this->fmtDateShort((string)($g['dob'] ?? '')) : '';
            if ($name !== '') $this->put($pdf,  28.0, $gy, $this->trunc($name, 30));
            if ($age  !== '') $this->put($pdf, 108.0, $gy, $age);
            if ($dob  !== '') $this->put($pdf, 130.0, $gy, $dob);
        }

        // Stay details
        $this->put($pdf,  48.0, 198.0, $this->fmtDateShort($d['check_in_date']  ?? ''));
        $this->put($pdf, 140.0, 198.0, $this->fmtDateShort($d['check_out_date'] ?? ''));
        $this->put($pdf,  48.0, 207.0, $this->fmtTime($d['check_in_time']  ?? ''));
        $this->put($pdf, 140.0, 207.0, $this->fmtTime($d['check_out_time'] ?? ''));
        $this->put($pdf,  48.0, 216.0, (string)(int)($d['adults_count']   ?? 0));
        $this->put($pdf, 140.0, 216.0, (string)(int)($d['children_count'] ?? 0));
        $this->put($pdf,  48.0, 225.0, (string)($d['room_name'] ?? ''));
        $this->put($pdf, 140.0, 225.0, ucfirst((string)($d['room_type'] ?? '')));

        // Remarks
        $remarks = trim((string)($d['special_requests'] ?? ''));
        if ($remarks !== '') {
            $pdf->SetFont('helvetica', '', 9);
            $pdf->SetTextColor(0, 0, 0);
            $pdf->SetXY(14.0, 235.0);
            $pdf->MultiCell(182.0, 4.5, $remarks, 0, 'L', false, 1);
        }

        // Registered by
        $regBy = trim((string)($d['terms_accepted_by'] ?? $d['registered_by'] ?? ''));
        $this->put($pdf, 48.0, 250.0, $regBy);
    }

    // ── Page 2 ────────────────────────────────────────────────────────────────

    private function renderPage2(\TCPDF $pdf): void
    {
        $pdf->AddPage();
        $this->bgFile($pdf, 2);

        $others = $this->decodeGuests($this->data['other_guests'] ?? '[]');
        $startY = 93.5;
        $lineH  = 8.15;

        for ($i = 0; $i < 24; $i++) {
            $g    = $others[4 + $i] ?? null;
            $name = $g ? trim((string)($g['name'] ?? '')) : '';
            $age  = $g ? trim((string)($g['age']  ?? '')) : '';
            $dob  = $g ? $this->fmtDateShort((string)($g['dob'] ?? '')) : '';
            $y    = $startY + ($i * $lineH);
            if ($name !== '') $this->put($pdf,  28.0, $y, $this->trunc($name, 30));
            if ($age  !== '') $this->put($pdf, 108.0, $y, $age);
            if ($dob  !== '') $this->put($pdf, 130.0, $y, $dob);
        }
    }

    // ── Page 3 ────────────────────────────────────────────────────────────────

    private function renderPage3(\TCPDF $pdf): void
    {
        $pdf->AddPage();
        $this->bgFile($pdf, 3);
        // Static guidelines page — no data to overlay
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private function splitName(string $full): array
    {
        $full = trim($full);
        if ($full === '') return ['', '', ''];
        $last = $first = $mi = '';
        if (str_contains($full, ',')) {
            [$lastPart, $rest] = array_map('trim', explode(',', $full, 2));
            $last  = $lastPart;
            $parts = preg_split('/\s+/', $rest) ?: [];
            $first = $parts[0] ?? '';
            $mi    = rtrim($parts[1] ?? '', '.');
        } else {
            $parts = preg_split('/\s+/', $full) ?: [];
            $n = count($parts);
            if ($n === 1) { $first = $parts[0]; }
            elseif ($n === 2) { [$first, $last] = $parts; }
            else { $first = $parts[0]; $last = $parts[$n - 1]; $mi = rtrim($parts[1], '.'); }
        }
        if ($mi !== '' && mb_strlen($mi) > 1) $mi = mb_strtoupper(mb_substr($mi, 0, 1));
        return [$last, $first, $mi];
    }

    private function decodeGuests(mixed $raw): array
    {
        if (is_array($raw)) return $raw;
        $decoded = json_decode((string)$raw, true);
        return is_array($decoded) ? $decoded : [];
    }

    private function fmtDate(string $d): string
    {
        $d = trim($d);
        if ($d === '' || $d === '0000-00-00') return '';
        $ts = strtotime($d);
        return $ts ? date('F d, Y', $ts) : '';
    }

    private function fmtDateShort(string $d): string
    {
        $d = trim($d);
        if ($d === '' || $d === '0000-00-00') return '';
        $ts = strtotime($d);
        return $ts ? date('M d, Y', $ts) : '';
    }

    private function fmtTime(string $t): string
    {
        $t = trim($t);
        if ($t === '') return '';
        $ts = strtotime('1970-01-01 ' . $t);
        return $ts ? date('h:i A', $ts) : '';
    }

    private function trunc(string $text, int $max): string
    {
        if (mb_strlen($text) <= $max) return $text;
        return mb_substr($text, 0, $max - 1) . '…';
    }

    // ── Embedded form page images (base64 JPEG) ───────────────────────────────
    private const PAGE1_B64 = '';
    private const PAGE2_B64 = '';
    private const PAGE3_B64 = '';
}